```javascript
const { PrismaClient } = require('@prisma/client')
const prisma = new PrismaClient()

async function getUsersWithComments() {
  const users = await prisma.user.findMany({
    select: {
      id: true,
      name: true,
      email: true,
      comments: {
        select: {
          id: true,
          text: true,
          createdAt: true,
          post: {
            select: {
              id: true,
              title: true
            }
          }
        },
        where: {
          createdAt: {
            gt: new Date('2022-01-01T00:00:00.000Z')
          }
        }
      }
    },
    where: {
      name: {
        contains: 'John'
      }
    }
  })

  console.log(users)
}

getUsersWithComments()
```

This query fetches all users whose name contains the string 'John' and their associated comments, but only selects specific fields from each data model. It also includes a `@where` directive on the `comments` field to fetch comments created after January 1st, 2022.

As you can see, Prisma's declarative syntax allows you to write complex queries with ease and makes it possible to fetch related data in a single query.
